The event 'connect' is not called. event is "disconnect" right away . Server on NodeJS with socket.io (v. 2.1.1), client on python (socketIO_client_nexus).
If i run client on NodeJs, all working and event 'connect' called.

client (nodejs):
```
const socketio = require('socket.io-client');

(async () => {
  let socket = null;
  let onLoginCb = null;

  socket = socketio('http://localhost:3000', {query: `email=mail@mail.com&password=password`})
  socket.on('connect', () => {
    console.log('connected')
  })

  socket.on('login', data => {
    console.log('data ', data)
  })
  socket.on('disconnect', reason => {
    console.log(`socket_disconnected ${reason}`)
  })
  socket.on('connect_error', error => {
    console.log(`connect_error ${error}`)
  })
  socket.on('reconnect_attempt', number => {
    console.log(`socket reconnect_attempt ${number}`)
  })
  socket.on('error', reason => {
    console.log(`socket error ${reason}`)
  })
})();
```

client (python):
```
import logging
from socketIO_client_nexus import SocketIO, LoggingNamespace, BaseNamespace
from requests.exceptions import ConnectionError

logging.getLogger('socketIO-client-nexus').setLevel(logging.DEBUG)
